CREATE TABLE `audit_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT 'ID пользователя, совершившего действие',
  `username` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Имя пользователя для удобства',
  `user_role` enum('ADMIN','MANAGER','LICENSE_MANAGER','PRESIDIUM_MEMBER') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Роль пользователя на момент действия',
  `action` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Тип действия (CREATE, UPDATE, DELETE, LOGIN, etc.)',
  `entity_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Тип сущности (tournament, player, team, user, etc.)',
  `entity_id` int DEFAULT NULL COMMENT 'ID сущности, над которой совершено действие',
  `entity_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Название сущности для удобства чтения',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT 'Подробное описание действия',
  `ip_address` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'IP адрес пользователя (поддержка IPv6)',
  `user_agent` text COLLATE utf8mb4_unicode_ci COMMENT 'User Agent браузера',
  `request_method` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'HTTP метод (GET, POST, PUT, DELETE)',
  `request_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'URL запроса',
  `request_body` json DEFAULT NULL COMMENT 'Тело запроса (без чувствительных данных)',
  `changes` json DEFAULT NULL COMMENT 'Изменения в формате JSON (old/new values)',
  `success` tinyint(1) DEFAULT '1' COMMENT 'Успешность операции',
  `error_message` text COLLATE utf8mb4_unicode_ci COMMENT 'Сообщение об ошибке, если не успешно',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Время выполнения действия',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_username` (`username`),
  KEY `idx_action` (`action`),
  KEY `idx_entity` (`entity_type`,`entity_id`),
  KEY `idx_created_at` (`created_at` DESC),
  KEY `idx_success` (`success`),
  KEY `idx_user_action` (`user_id`,`action`),
  KEY `idx_entity_type` (`entity_type`),
  CONSTRAINT `audit_logs_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=2080 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Логи действий пользователей в системе';
