  PRIMARY KEY (`id`),
  UNIQUE KEY `name` (`name`),
  UNIQUE KEY `license_number` (`license_number`),
  KEY `idx_name` (`name`),
  KEY `idx_gender` (`gender`),
  KEY `idx_city` (`city`),
