--
-- Table structure for table `tournaments`
--

DROP TABLE IF EXISTS `tournaments`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tournaments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `type` enum('TRIPLETTE','DOUBLETTE_MALE','DOUBLETTE_FEMALE','DOUBLETTE_MIXT','TET_A_TET_MALE','TET_A_TET_FEMALE') NOT NULL,
  `category` enum('FEDERAL','REGIONAL') NOT NULL DEFAULT 'REGIONAL',
  `date` date NOT NULL,
  `manual` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'TRUE при обработке результатов турнира с листа "Ручной ввод"',
  `status` varchar(32) NOT NULL DEFAULT 'FINISHED' COMMENT 'FINISHED | REGISTRATION | IN_PROGRESS',
  `regulations` text COMMENT 'Описание турнира (текст)',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `results_validated_at` timestamp NULL DEFAULT NULL COMMENT 'Признание президиумом: результаты учитываются в рейтинге',
  PRIMARY KEY (`id`),
  KEY `idx_date` (`date`),
  KEY `idx_category` (`category`)
) ENGINE=InnoDB AUTO_INCREMENT=124 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

